func getBundlesJSON(bundles []models.Bundle) string {
	if len(bundles) == 0 {
		return "[]"
	}
	// Create a copy to sort
	sorted := make([]models.Bundle, len(bundles))
	copy(sorted, bundles)
	sort.Slice(sorted, func(i, j int) bool {
		return sorted[i].Quantity < sorted[j].Quantity
	})
	b, _ := json.Marshal(sorted)
	return string(b)
}

